resource "aws_s3_bucket" "elb_logs" {
  bucket = "elb-access-logs-bucket"

  # Enable bucket encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Enable versioning for additional protection
  versioning {
    enabled = true
  }

  # Block public access to the bucket
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  tags = {
    Name = "ELB Access Logs Bucket"
  }
}

# Create bucket policy to allow ELB to write logs
resource "aws_s3_bucket_policy" "elb_logs_policy" {
  bucket = aws_s3_bucket.elb_logs.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::127311923021:root"
        }
        Action = "s3:PutObject"
        Resource = "${aws_s3_bucket.elb_logs.arn}/AWSLogs/*"
      }
    ]
  })
}"
}

