      enable_integrity_monitoring = true
    }

    # Use least privilege service account
    service_account = "gke-sa@${var.project}.iam.gserviceaccount.com"

    # Restrict Scopes
    oauth_scopes = [
      "https://www.googleapis.com/auth/cloud-platform"
    ]

